import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [tab, setTab] = useState('users');
  const [themeTrigger, setThemeTrigger] = useState(false);

  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data));
    API.get('/admin/posts').then(res => setPosts(res.data));
    API.get('/admin/comments').then(res => setComments(res.data));
  }, []);

  useEffect(() => {
    const handleThemeChange = () => setThemeTrigger(prev => !prev);
    window.addEventListener("storage", handleThemeChange);
    return () => window.removeEventListener("storage", handleThemeChange);
  }, []);

  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(users.map(u => (u._id === id ? data.user : u)));
  };

  const removePost = async (id) => {
    if (!window.confirm("Permanently delete this post? This cannot be undone.")) return;
    try {
      await API.delete(`/posts/${id}`); 
      setPosts(posts.filter(p => p._id !== id));
    } catch (err) {
      alert("Error deleting post.");
    }
  };

  const deleteComment = async (id) => {
    await API.delete(`/comments/${id}`);
    setComments(comments.filter(c => c._id !== id));
  };

  const viewPost = (postId) => {
    // Ensure this matches your route definition exactly
    navigate(`/post/${postId}`);
  };

  const isDark = document.body.classList.contains('dark-mode');

  const styles = {
    page: {
      backgroundColor: isDark ? '#560032' : '#FAE8ED',
      minHeight: '100vh',
      padding: '40px 20px',
      fontFamily: '"Segoe UI", Roboto, Helvetica, Arial, sans-serif',
      color: isDark ? '#f5d6e6' : 'rgb(12, 75, 52)',
    },
    container: {
      maxWidth: '1200px',
      margin: '0 auto',
      backgroundColor: isDark ? '#2e091e' : '#ffffff',
      padding: '40px',
      borderRadius: '24px',
      boxShadow: '0 15px 35px rgba(0,0,0,0.15)',
    },
    heading: {
      fontSize: '32px',
      textAlign: 'center',
      marginBottom: '30px',
      fontWeight: '800',
      letterSpacing: '-0.5px'
    },
    tabs: {
      display: 'flex',
      justifyContent: 'center',
      gap: '15px',
      marginBottom: '40px',
    },
    tabButton: {
      padding: '12px 24px',
      borderRadius: '12px',
      border: 'none',
      cursor: 'pointer',
      fontWeight: 'bold',
      fontSize: '15px',
      backgroundColor: isDark ? '#3a253a' : '#f0f0f0',
      color: isDark ? '#f5d6e6' : '#666',
      transition: 'all 0.2s ease',
    },
    activeTab: {
      backgroundColor: isDark ? '#eda0ae' : 'rgb(12, 75, 52)',
      color: '#fff',
      transform: 'translateY(-2px)',
      boxShadow: '0 4px 12px rgba(0,0,0,0.15)'
    },
    table: {
      width: '100%',
      borderCollapse: 'separate',
      borderSpacing: '0 8px', // Spacing between rows
      tableLayout: 'fixed', // Keeps columns consistent
    },
    th: {
      padding: '15px',
      color: isDark ? '#eda0ae' : 'rgb(12, 75, 52)',
      textAlign: 'left',
      fontWeight: '700',
      borderBottom: `2px solid ${isDark ? '#4a2e4a' : '#f0f0f0'}`,
    },
    td: {
      padding: '15px',
      backgroundColor: isDark ? '#3a253a' : '#fdfdfd',
      color: isDark ? '#f5d6e6' : '#333',
      borderBottom: isDark ? '1px solid #4a2e4a' : '1px solid #eee',
    },
    actionCell: {
      display: 'flex',
      gap: '10px',
      justifyContent: 'flex-start',
      alignItems: 'center',
    },
    button: {
      padding: '8px 16px',
      borderRadius: '8px',
      border: 'none',
      cursor: 'pointer',
      fontWeight: 'bold',
      fontSize: '12px',
      transition: 'opacity 0.2s',
      display: 'inline-flex',
      alignItems: 'center',
      gap: '5px'
    },
    dangerBtn: { backgroundColor: '#ff4d6d', color: '#fff' },
    viewBtn: { backgroundColor: '#6c63ff', color: '#fff' },
    statusBtn: { backgroundColor: 'rgb(12, 75, 52)', color: '#fff' }
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>System Administration</h2>

        <div style={styles.tabs}>
          {['users', 'posts', 'comments'].map((t) => (
            <button
              key={t}
              onClick={() => setTab(t)}
              style={{ ...styles.tabButton, ...(tab === t ? styles.activeTab : {}) }}
            >
              {t.charAt(0).toUpperCase() + t.slice(1)} ({t === 'users' ? users.length : t === 'posts' ? posts.length : comments.length})
            </button>
          ))}
        </div>

        <div style={{ overflowX: 'auto' }}>
          <table style={styles.table}>
            <thead>
              {tab === 'users' && (
                <tr>
                  <th style={{ ...styles.th, width: '30%' }}>User</th>
                  <th style={{ ...styles.th, width: '40%' }}>Email</th>
                  <th style={{ ...styles.th, width: '15%' }}>Status</th>
                  <th style={{ ...styles.th, width: '15%' }}>Action</th>
                </tr>
              )}
              {tab === 'posts' && (
                <tr>
                  <th style={{ ...styles.th, width: '45%' }}>Post Title</th>
                  <th style={{ ...styles.th, width: '25%' }}>Author</th>
                  <th style={{ ...styles.th, width: '30%' }}>Actions</th>
                </tr>
              )}
              {tab === 'comments' && (
                <tr>
                  <th style={{ ...styles.th, width: '25%' }}>Author</th>
                  <th style={{ ...styles.th, width: '55%' }}>Comment Body</th>
                  <th style={{ ...styles.th, width: '20%' }}>Action</th>
                </tr>
              )}
            </thead>
            <tbody>
              {tab === 'users' && users.map(u => (
                <tr key={u._id}>
                  <td style={styles.td}><strong>{u.name}</strong></td>
                  <td style={styles.td}>{u.email}</td>
                  <td style={styles.td}>{u.status}</td>
                  <td style={styles.td}>
                    <button style={{ ...styles.button, ...styles.statusBtn }} onClick={() => toggleStatus(u._id)}>
                      {u.status === 'active' ? 'Ban' : 'Unban'}
                    </button>
                  </td>
                </tr>
              ))}

              {tab === 'posts' && posts.map(p => (
                <tr key={p._id}>
                  <td style={{ ...styles.td, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                    <strong>{p.title}</strong>
                  </td>
                  <td style={styles.td}>{p.author?.name || 'Deleted User'}</td>
                  <td style={styles.td}>
                    <div style={styles.actionCell}>
                      <button style={{ ...styles.button, ...styles.viewBtn }} onClick={() => viewPost(p._id)}>
                        👁 View
                      </button>
                      <button style={{ ...styles.button, ...styles.dangerBtn }} onClick={() => removePost(p._id)}>
                        🗑 Delete
                      </button>
                    </div>
                  </td>
                </tr>
              ))}

              {tab === 'comments' && comments.map(c => (
                <tr key={c._id}>
                  <td style={styles.td}><strong>{c.author?.name}</strong></td>
                  <td style={styles.td}>{c.body}</td>
                  <td style={styles.td}>
                    <button style={{ ...styles.button, ...styles.dangerBtn }} onClick={() => deleteComment(c._id)}>
                      Remove
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminPage;
